package com.example.offlineshapealarm.alarm
import android.app.*; import android.content.*; import android.net.Uri; import android.os.*; import android.view.*; import android.widget.*
class AlarmActivity: Activity(){ private var start=0L; private val handler=Handler(Looper.getMainLooper()); private lateinit var progress:ProgressBar; private var alarmId:String=""
 override fun onCreate(b:Bundle?){ super.onCreate(b); alarmId=intent.getStringExtra("alarmId") ?: ""; if(Build.VERSION.SDK_INT>=27){ setShowWhenLocked(true); setTurnScreenOn(true) } else @Suppress("DEPRECATION") window.addFlags(WindowManager.LayoutParams.FLAG_SHOW_WHEN_LOCKED or WindowManager.LayoutParams.FLAG_TURN_SCREEN_ON); val label=intent.getStringExtra("label") ?: "Alarm"; val challengeName=when(intent.getStringExtra("challengeType")){ "quick-addition" -> "quick addition challenge"; "connect-dots" -> "connect the dots challenge"; else -> "shape photo challenge" }; val root=LinearLayout(this).apply{ orientation=LinearLayout.VERTICAL; gravity=Gravity.CENTER; setPadding(48,48,48,48) }; root.addView(TextView(this).apply{text=label; textSize=30f; gravity=Gravity.CENTER}); root.addView(TextView(this).apply{text="Complete the $challengeName to dismiss this alarm."; gravity=Gravity.CENTER}); root.addView(Button(this).apply{text="Open challenge"; setOnClickListener{ startActivity(Intent(Intent.ACTION_VIEW, Uri.parse("shapealarm://challenge/$alarmId")).setPackage(packageName).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK)); finish() }}); progress=ProgressBar(this,null,android.R.attr.progressBarStyleHorizontal).apply{max=10000}; root.addView(progress, LinearLayout.LayoutParams(-1,-2)); root.addView(Button(this).apply{text="Emergency override: hold 10 seconds"; wire(this,10000,"emergency-override")}); setContentView(root) }
 private fun wire(button:Button, required:Long, reason:String){ val tick=object:Runnable{ override fun run(){ val elapsed=System.currentTimeMillis()-start; progress.max=required.toInt(); progress.progress=elapsed.toInt(); if(elapsed>=required){ stop(reason) } else handler.postDelayed(this,50) } }; button.setOnTouchListener{_,e -> when(e.action){ MotionEvent.ACTION_DOWN -> { start=System.currentTimeMillis(); handler.post(tick); true }; MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> { handler.removeCallbacks(tick); progress.progress=0; true }; else -> false } } }
 private fun stop(reason:String){ handler.removeCallbacksAndMessages(null); startService(Intent(this, AlarmForegroundService::class.java).setAction(AlarmForegroundService.ACTION_STOP_ALARM).putExtra("alarmId",alarmId).putExtra("reason",reason)); finish() }
}
